  1→import { useCallback, useRef, useState, useEffect } from "react";
  2→import {
  3→  ReactFlow,
  4→  MiniMap,
  5→  Controls,
  6→  Background,
  7→  useReactFlow,
  8→  ReactFlowProvider,
  9→  applyNodeChanges,
 10→  applyEdgeChanges,
 11→  type Node,
 12→  type Edge,
 13→  type OnNodesChange,
 14→  type OnEdgesChange,
 15→  type OnConnect,
 16→  type Connection,
 17→  type NodeTypes,
 18→  type EdgeTypes,
 19→} from "@xyflow/react";
 20→import "@xyflow/react/dist/style.css";
 21→
 22→import { NodeCard, type NodeCardData } from "./NodeCard";
 23→import { type PortType, type NodeDefinition } from "@/lib/types";
 24→
 25→// ── Port-type validation (pure function) ─────────────────────────────
 26→
 27→export function arePortTypesCompatible(
 28→  sourceType: PortType | undefined,
 29→  targetType: PortType | undefined,
 30→): boolean {
 31→  if (!sourceType || !targetType) return false;
 32→  return sourceType === targetType;
 33→}
 34→
 35→// ── Custom node / edge types ─────────────────────────────────────────
 36→
 37→const nodeTypes: NodeTypes = {
 38→  nodeCard: NodeCard,
 39→};
 40→
 41→// Placeholder edge type for conditional edges (T12 will implement fully)
 42→const edgeTypes: EdgeTypes = {};
 43→
 44→// ── History for undo/redo ────────────────────────────────────────────
 45→
 46→interface CanvasSnapshot {
 47→  nodes: Node<NodeCardData>[];
 48→  edges: Edge[];
 49→}
 50→
 51→function useHistory(initial: CanvasSnapshot) {
 52→  const stack = useRef<CanvasSnapshot[]>([initial]);
 53→  const pointer = useRef(0);
 54→
 55→  const push = useCallback((snapshot: CanvasSnapshot) => {
 56→    stack.current = stack.current.slice(0, pointer.current + 1);
 57→    stack.current.push(snapshot);
 58→    pointer.current = stack.current.length - 1;
 59→  }, []);
 60→
 61→  const undo = useCallback((): CanvasSnapshot | null => {
 62→    if (pointer.current > 0) {
 63→      pointer.current -= 1;
 64→      return stack.current[pointer.current] ?? null;
 65→    }
 66→    return null;
 67→  }, []);
 68→
 69→  const redo = useCallback((): CanvasSnapshot | null => {
 70→    if (pointer.current < stack.current.length - 1) {
 71→      pointer.current += 1;
 72→      return stack.current[pointer.current] ?? null;
 73→    }
 74→    return null;
 75→  }, []);
 76→
 77→  return { push, undo, redo };
 78→}
 79→
 80→// ── Canvas inner (needs ReactFlowProvider) ───────────────────────────
 81→
 82→export interface CanvasProps {
 83→  nodes?: Node<NodeCardData>[];
 84→  edges?: Edge[];
 85→  onNodesChange?: OnNodesChange<Node<NodeCardData>>;
 86→  onEdgesChange?: OnEdgesChange;
 87→  onConnect?: OnConnect;
 88→  onNodeSelect?: (nodeId?: string, tab?: string) => void;
 89→}
 90→
 91→let nodeIdCounter = 0;
 92→
 93→function CanvasInner({
 94→  nodes: controlledNodes,
 95→  edges: controlledEdges,
 96→  onNodesChange: controlledOnNodesChange,
 97→  onEdgesChange: controlledOnEdgesChange,
 98→  onConnect: controlledOnConnect,
 99→  onNodeSelect,
100→}: CanvasProps) {
101→  const isControlled = controlledNodes !== undefined;
102→
103→  const [internalNodes, setInternalNodes] = useState<Node<NodeCardData>[]>([]);
104→  const [internalEdges, setInternalEdges] = useState<Edge[]>([]);
105→
106→  const nodes = isControlled ? controlledNodes : internalNodes;
107→  const edges = isControlled ? (controlledEdges ?? []) : internalEdges;
108→
109→  const { screenToFlowPosition } = useReactFlow();
110→  const history = useHistory({ nodes: [], edges: [] });
111→
112→  // Push snapshot to history for undo
113→  const pushHistory = useCallback(
114→    (n: Node<NodeCardData>[], e: Edge[]) => {
115→      history.push({ nodes: n, edges: e });
116→    },
117→    [history],
118→  );
119→
120→  // ── Node / edge change handlers ──────────────────────────────────
121→
122→  const onNodesChange: OnNodesChange<Node<NodeCardData>> = useCallback(
123→    (changes) => {
124→      if (isControlled) {
125→        controlledOnNodesChange?.(changes);
126→        return;
127→      }
128→      setInternalNodes((nds) => {
129→        const next = applyNodeChanges(changes, nds);
130→        // Push history on remove
131→        const hasRemove = changes.some((c) => c.type === "remove");
132→        if (hasRemove) {
133→          // edges may also change, but we push current edges
134→          pushHistory(next, internalEdges);
135→        }
136→        return next;
137→      });
138→    },
139→    [isControlled, controlledOnNodesChange, pushHistory, internalEdges],
140→  );
141→
142→  const onEdgesChange: OnEdgesChange = useCallback(
143→    (changes) => {
144→      if (isControlled) {
145→        controlledOnEdgesChange?.(changes);
146→        return;
147→      }
148→      setInternalEdges((eds) => {
149→        const next = applyEdgeChanges(changes, eds);
150→        const hasRemove = changes.some((c) => c.type === "remove");
151→        if (hasRemove) {
152→          pushHistory(internalNodes, next);
153→        }
154→        return next;
155→      });
156→    },
157→    [isControlled, controlledOnEdgesChange, pushHistory, internalNodes],
158→  );
159→
160→  // ── Connect handler with port-type validation ────────────────────
161→
162→  const onConnect: OnConnect = useCallback(
163→    (connection: Connection) => {
164→      if (isControlled) {
165→        controlledOnConnect?.(connection);
166→        return;
167→      }
168→
169→      const sourceNode = internalNodes.find((n) => n.id === connection.source);
170→      const targetNode = internalNodes.find((n) => n.id === connection.target);
171→
172→      const sourcePort = sourceNode?.data?.definition?.outputs?.find(
173→        (p) => p.name === connection.sourceHandle,
174→      );
175→      const targetPort = targetNode?.data?.definition?.inputs?.find(
176→        (p) => p.name === connection.targetHandle,
177→      );
178→
179→      if (!arePortTypesCompatible(sourcePort?.type, targetPort?.type)) {
180→        // Flash the target handle red
181→        const handleEl = document.querySelector(
182→          `.react-flow__handle[data-handleid="${connection.targetHandle}"][data-nodeid="${connection.target}"]`,
183→        );
184→        if (handleEl) {
185→          handleEl.classList.add("handle-flash-red");
186→          setTimeout(() => handleEl.classList.remove("handle-flash-red"), 600);
187→        }
188→        return;
189→      }
190→
191→      const newEdge: Edge = {
192→        id: `e-${connection.source}-${connection.sourceHandle}-${connection.target}-${connection.targetHandle}`,
193→        source: connection.source!,
194→        sourceHandle: connection.sourceHandle,
195→        target: connection.target!,
196→        targetHandle: connection.targetHandle,
197→      };
198→
199→      setInternalEdges((eds) => {
200→        const next = [...eds, newEdge];
201→        pushHistory(internalNodes, next);
202→        return next;
203→      });
204→    },
205→    [isControlled, controlledOnConnect, internalNodes, pushHistory],
206→  );
207→
208→  // ── Node drag end → push history ─────────────────────────────────
209→
210→  const onNodeDragStop = useCallback(() => {
211→    if (!isControlled) {
212→      // Defer to capture the updated node positions
213→      setTimeout(() => {
214→        setInternalNodes((nds) => {
215→          pushHistory(nds, internalEdges);
216→          return nds;
217→        });
218→      }, 0);
219→    }
220→  }, [isControlled, pushHistory, internalEdges]);
221→
222→  // ── Tab click handler (passed to each node via data) ─────────────
223→
224→  const handleTabClick = useCallback(
225→    (nodeId: string, tab: string) => {
226→      onNodeSelect?.(nodeId, tab);
227→    },
228→    [onNodeSelect],
229→  );
230→
231→  // Inject onTabClick into node data
232→  const nodesWithCallbacks = nodes.map((node) => ({
233→    ...node,
234→    data: {
235→      ...node.data,
236→      onTabClick: handleTabClick,
237→    },
238→  }));
239→
240→  // ── Keyboard shortcuts ───────────────────────────────────────────
241→
242→  useEffect(() => {
243→    const handler = (e: KeyboardEvent) => {
244→      // Undo: Ctrl+Z (without shift)
245→      if (e.key === "z" && (e.ctrlKey || e.metaKey) && !e.shiftKey) {
246→        e.preventDefault();
247→        const snapshot = history.undo();
248→        if (snapshot && !isControlled) {
249→          setInternalNodes(snapshot.nodes);
250→          setInternalEdges(snapshot.edges);
251→        }
252→      }
253→      // Redo: Ctrl+Shift+Z
254→      if (e.key === "z" && (e.ctrlKey || e.metaKey) && e.shiftKey) {
255→        e.preventDefault();
256→        const snapshot = history.redo();
257→        if (snapshot && !isControlled) {
258→          setInternalNodes(snapshot.nodes);
259→          setInternalEdges(snapshot.edges);
260→        }
261→      }
262→    };
263→
264→    window.addEventListener("keydown", handler);
265→    return () => window.removeEventListener("keydown", handler);
266→  }, [history, isControlled]);
267→
268→  // ── Drag-and-drop from sidebar ───────────────────────────────────
269→
270→  const onDragOver = useCallback((event: React.DragEvent) => {
271→    event.preventDefault();
272→    event.dataTransfer.dropEffect = "move";
273→  }, []);
274→
275→  const onDrop = useCallback(
276→    (event: React.DragEvent) => {
277→      event.preventDefault();
278→      const raw = event.dataTransfer.getData("application/reactflow");
279→      if (!raw) return;
280→
281→      let definition: NodeDefinition;
282→      try {
283→        definition = JSON.parse(raw);
284→      } catch {
285→        return;
286→      }
287→
288→      const position = screenToFlowPosition({
289→        x: event.clientX,
290→        y: event.clientY,
291→      });
292→
293→      nodeIdCounter += 1;
294→      const newNodeId = `node-${Date.now()}-${nodeIdCounter}`;
295→
296→      // Build default params from definition
297→      const defaultParams: Record<string, string | number | boolean> = {};
298→      for (const p of definition.params) {
299→        defaultParams[p.name] = p.default;
300→      }
301→
302→      const newNode: Node<NodeCardData> = {
303→        id: newNodeId,
304→        type: "nodeCard",
305→        position,
306→        data: {
307→          label: definition.label,
308→          definition,
309→          status: "idle",
310→          params: defaultParams,
311→        },
312→      };
313→
314→      if (isControlled) {
315→        // In controlled mode, the parent handles adding nodes
316→        return;
317→      }
318→
319→      setInternalNodes((nds) => {
320→        const next = [...nds, newNode];
321→        pushHistory(next, internalEdges);
322→        return next;
323→      });
324→    },
325→    [screenToFlowPosition, isControlled, pushHistory, internalEdges],
326→  );
327→
328→  return (
329→    <div className="h-full w-full" onDragOver={onDragOver} onDrop={onDrop}>
330→      <ReactFlow
331→        nodes={nodesWithCallbacks}
332→        edges={edges}
333→        onNodesChange={onNodesChange}
334→        onEdgesChange={onEdgesChange}
335→        onConnect={onConnect}
336→        onNodeDragStop={onNodeDragStop}
337→        nodeTypes={nodeTypes}
338→        edgeTypes={edgeTypes}
339→        deleteKeyCode="Delete"
340→        fitView
341→        className="bg-[#1a1a1e]"
342→      >
343→        <Background color="#333" gap={20} />
344→        <Controls className="!bg-[#27272a] !border-[#3f3f46] !rounded-lg [&>button]:!bg-[#27272a] [&>button]:!border-[#3f3f46] [&>button]:!fill-[#a1a1aa] [&>button:hover]:!bg-[#3f3f46]" />
345→        <MiniMap
346→          position="bottom-right"
347→          className="!bg-[#27272a] !border-[#3f3f46] !rounded-lg"
348→          maskColor="rgba(0,0,0,0.5)"
349→          nodeColor="#3B82F6"
350→        />
351→      </ReactFlow>
352→    </div>
353→  );
354→}
355→
356→// ── Wrapped export with ReactFlowProvider ────────────────────────────
357→
358→export function Canvas(props: CanvasProps) {
359→  return (
360→    <ReactFlowProvider>
361→      <CanvasInner {...props} />
362→    </ReactFlowProvider>
363→  );
364→}
