  1→import { useState } from "react";
  2→import { type NodeDefinition, type PortType, PORT_COLORS } from "@/lib/types";
  3→
  4→interface SidebarProps {
  5→  definitions: NodeDefinition[];
  6→}
  7→
  8→function PortDot({ type }: { type: PortType }) {
  9→  return (
 10→    <span
 11→      className="inline-block h-2 w-2 rounded-full"
 12→      style={{ backgroundColor: PORT_COLORS[type] }}
 13→      title={type}
 14→    />
 15→  );
 16→}
 17→
 18→function NodeTypeCard({ definition }: { definition: NodeDefinition }) {
 19→  const onDragStart = (event: React.DragEvent) => {
 20→    event.dataTransfer.setData(
 21→      "application/reactflow",
 22→      JSON.stringify(definition),
 23→    );
 24→    event.dataTransfer.effectAllowed = "move";
 25→  };
 26→
 27→  return (
 28→    <div
 29→      className="cursor-grab rounded-md border border-border bg-secondary p-2.5 transition-colors hover:border-ring active:cursor-grabbing"
 30→      draggable
 31→      onDragStart={onDragStart}
 32→    >
 33→      <div className="mb-1 text-xs font-medium text-foreground">
 34→        {definition.label}
 35→      </div>
 36→      <div className="flex items-center gap-2 text-[10px] text-muted-foreground">
 37→        {definition.inputs.length > 0 && (
 38→          <span className="flex items-center gap-1">
 39→            In:
 40→            {definition.inputs.map((p) => (
 41→              <PortDot key={p.name} type={p.type} />
 42→            ))}
 43→          </span>
 44→        )}
 45→        {definition.outputs.length > 0 && (
 46→          <span className="flex items-center gap-1">
 47→            Out:
 48→            {definition.outputs.map((p) => (
 49→              <PortDot key={p.name} type={p.type} />
 50→            ))}
 51→          </span>
 52→        )}
 53→      </div>
 54→    </div>
 55→  );
 56→}
 57→
 58→export function NodeLibrarySidebar({ definitions }: SidebarProps) {
 59→  const [search, setSearch] = useState("");
 60→
 61→  const filtered = definitions.filter(
 62→    (d) =>
 63→      d.label.toLowerCase().includes(search.toLowerCase()) ||
 64→      d.category.toLowerCase().includes(search.toLowerCase()),
 65→  );
 66→
 67→  // Group by category
 68→  const grouped = filtered.reduce<Record<string, NodeDefinition[]>>(
 69→    (acc, def) => {
 70→      (acc[def.category] ??= []).push(def);
 71→      return acc;
 72→    },
 73→    {},
 74→  );
 75→
 76→  return (
 77→    <div className="flex h-full flex-col">
 78→      <div className="border-b border-border px-4 py-3">
 79→        <h2 className="mb-2 text-sm font-semibold text-foreground">
 80→          Node Library
 81→        </h2>
 82→        <input
 83→          type="text"
 84→          placeholder="Search nodes..."
 85→          value={search}
 86→          onChange={(e) => setSearch(e.target.value)}
 87→          className="w-full rounded-md border border-border bg-input px-2.5 py-1.5 text-xs text-foreground placeholder:text-muted-foreground focus:border-ring focus:outline-none"
 88→        />
 89→      </div>
 90→      <div className="flex-1 overflow-y-auto px-4 py-3">
 91→        {Object.entries(grouped).map(([category, defs]) => (
 92→          <div key={category} className="mb-4">
 93→            <h3 className="mb-1.5 text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">
 94→              {category}
 95→            </h3>
 96→            <div className="flex flex-col gap-1.5">
 97→              {defs.map((def) => (
 98→                <NodeTypeCard key={def.type} definition={def} />
 99→              ))}
100→            </div>
101→          </div>
102→        ))}
103→        {filtered.length === 0 && (
104→          <p className="text-xs text-muted-foreground">No nodes found.</p>
105→        )}
106→      </div>
107→    </div>
108→  );
109→}
