 1→// ── Port & Param types ──────────────────────────────────────────────
 2→
 3→export enum PortType {
 4→  TABLE = "TABLE",
 5→  MODEL = "MODEL",
 6→  METRICS = "METRICS",
 7→  ARRAY = "ARRAY",
 8→  VALUE = "VALUE",
