33→  default: string | number | boolean;
34→  options?: string[];
35→  min?: number;
36→  max?: number;
37→  step?: number;
38→}
39→
40→export interface NodeDefinition {
41→  type: string;
42→  label: string;
43→  category: string;
44→  description: string;
45→  inputs: NodePort[];
46→  outputs: NodePort[];
47→  params: NodeParam[];
48→  default_code?: string;
49→}
