    if (pointer.current > 0) {
      pointer.current -= 1;
      return stack.current[pointer.current] ?? null;
    }
    return null;
  }, []);

  const redo = useCallback((): CanvasSnapshot | null => {
    if (pointer.current < stack.current.length - 1) {
