        <Controls className="!bg-[#27272a] !border-[#3f3f46] !rounded-lg [&>button]:!bg-[#27272a] [&>button]:!border-[#3f3f46] [&>button]:!fill-[#a1a1aa] [&>button:hover]:!bg-[#3f3f46]" />
